import numpy as np
from scipy.spatial import ConvexHull

def select_next_node(current_node, destination_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return destination_node

    # Calculate pairwise distances among unvisited nodes to find clusters
    pairwise_distances = distance_matrix[np.ix_(unvisited_nodes, unvisited_nodes)]

    if len(unvisited_nodes) > 2:
        try:
            hull = ConvexHull(pairwise_distances)
            hull_nodes = unvisited_nodes[list(set(hull.vertices))]
            center_node = hull_nodes[np.argmin(distance_matrix[current_node, hull_nodes])]
        except:
            center_node = unvisited_nodes[np.argmin(distance_matrix[current_node, unvisited_nodes])]
    else:
        center_node = unvisited_nodes[np.argmin(distance_matrix[current_node, unvisited_nodes])]

    # Choose between the nearest node in the convex hull and the most isolated node
    if np.random.rand() > 0.5:
        next_node = center_node
    else:
        # Isolated node: node with max sum of distances to all other nodes
        isolation_scores = np.sum(pairwise_distances, axis=1)
        most_isolated_index = np.argmax(isolation_scores)
        next_node = unvisited_nodes[most_isolated_index]

    return next_node
